CREATE OR REPLACE FUNCTION add_points_to_user(user_id UUID, pts INT)
RETURNS VOID AS $$
BEGIN
  UPDATE profiles
  SET points = points + pts
  WHERE id = user_id;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

